import{_ as r,o as a,c as l,ag as i}from"./chunks/framework.C6K0jwmI.js";const b=JSON.parse('{"title":"Part 8 — トラブルシューティング（超詳細版）","description":"","frontmatter":{"title":"Part 8 — トラブルシューティング（超詳細版）","audience":"全員","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-19T00:00:00.000Z"},"headers":[],"relativePath":"operations/part8-troubleshooting.md","filePath":"operations/part8-troubleshooting.md"}'),o={name:"operations/part8-troubleshooting.md"};function d(e,t,n,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="part-8-—-トラブルシューティング-困ったとき" tabindex="-1">Part 8 — トラブルシューティング（困ったとき） <a class="header-anchor" href="#part-8-—-トラブルシューティング-困ったとき" aria-label="Permalink to &quot;Part 8 — トラブルシューティング（困ったとき）&quot;">​</a></h1><p>このページでは、営業中によく起きるトラブルと、<strong>その場での対処法</strong> を順序立てて説明します。</p><div class="tip custom-block"><p class="custom-block-title">基本の復旧 3 ステップ</p><p>何が起きても、まず以下の 3 つを試してください。</p><ol><li><strong>ブラウザをリロード</strong>（Cmd+Shift+R / Ctrl+Shift+F5）</li><li><strong>Wi-Fi 接続を確認</strong>（画面右上のアイコン）</li><li><strong>1 分待って再試行</strong></li></ol><p>これで 6 割のトラブルは解消します。それでもダメなら下の詳細手順へ。</p></div><hr><h2 id="_8-0-エラーが出たら-2026-04-19-追加" tabindex="-1">8-0. エラーが出たら（2026-04-19 追加） <a class="header-anchor" href="#_8-0-エラーが出たら-2026-04-19-追加" aria-label="Permalink to &quot;8-0. エラーが出たら（2026-04-19 追加）&quot;">​</a></h2><p>POSLA でエラーが出ると、画面に **以下のような形式で「番号付きメッセージ」**が出ます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[E3024] PIN が一致しません</span></span></code></pre></div><h3 id="_8-0-1-やること-バイトスタッフ向け" tabindex="-1">8-0-1. やること（バイトスタッフ向け） <a class="header-anchor" href="#_8-0-1-やること-バイトスタッフ向け" aria-label="Permalink to &quot;8-0-1. やること（バイトスタッフ向け）&quot;">​</a></h3><ol><li><strong>番号（<code>Exxxx</code>）を控える</strong>（紙にメモ・スクショ・声に出す）</li><li><strong>マネージャーに伝える</strong>（口頭でOK）</li><li>マネージャーが管理画面の <strong>オレンジ ? ボタン（右下）</strong> で AI に質問して対処方法を引き出す</li></ol><h3 id="_8-0-2-スタッフは-ai-ヘルプデスクを使わない" tabindex="-1">8-0-2. スタッフは AI ヘルプデスクを使わない <a class="header-anchor" href="#_8-0-2-スタッフは-ai-ヘルプデスクを使わない" aria-label="Permalink to &quot;8-0-2. スタッフは AI ヘルプデスクを使わない&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">スタッフ用端末（KDS / レジ / ハンディ）には AI ヘルプデスクのボタン（FAB）はありません</p><ul><li>スタッフが操作で困ったときは <strong>必ずマネージャーに聞く</strong> のが POSLA の運用ルールです</li><li>AI ヘルプデスクは管理画面（dashboard / owner-dashboard）にだけ設置されています</li><li>業務中の操作集中度を保つため、KDS・レジ・ハンディの画面には何も置きません</li></ul></div><h3 id="_8-0-3-マネージャー向け-エラー番号の調べ方" tabindex="-1">8-0-3. マネージャー向け：エラー番号の調べ方 <a class="header-anchor" href="#_8-0-3-マネージャー向け-エラー番号の調べ方" aria-label="Permalink to &quot;8-0-3. マネージャー向け：エラー番号の調べ方&quot;">​</a></h3><ol><li>管理画面（<code>dashboard.html</code> や <code>owner-dashboard.html</code>）右下の <strong>オレンジ色 ? ボタン</strong> をタップ</li><li>チャットパネルが開いたら、<code>[E3024]</code> のように番号をそのまま貼り付ける</li><li>AI がエラーカタログ（章 99）と該当章を照合して対処方法を返す</li></ol><p>エラー番号の桁の意味（参考）:</p><table tabindex="0"><thead><tr><th>範囲</th><th>系統</th></tr></thead><tbody><tr><td>E1xxx</td><td>認証・セッション</td></tr><tr><td>E2xxx</td><td>入力ミス</td></tr><tr><td>E3xxx</td><td>会計・PIN・決済</td></tr><tr><td>E4xxx</td><td>注文・KDS</td></tr><tr><td>E5xxx</td><td>在庫・メニュー</td></tr><tr><td>E6xxx</td><td>予約</td></tr><tr><td>E7xxx</td><td>印刷</td></tr><tr><td>E8xxx</td><td>外部 API</td></tr><tr><td>E9xxx</td><td>サーバー側（POSLA 運営マター）</td></tr></tbody></table><hr><h2 id="_8-1-ログインできない" tabindex="-1">8-1. ログインできない <a class="header-anchor" href="#_8-1-ログインできない" aria-label="Permalink to &quot;8-1. ログインできない&quot;">​</a></h2><h3 id="_8-1-1-エラーメッセージ別の対処" tabindex="-1">8-1-1. エラーメッセージ別の対処 <a class="header-anchor" href="#_8-1-1-エラーメッセージ別の対処" aria-label="Permalink to &quot;8-1-1. エラーメッセージ別の対処&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エラー文言</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「ユーザー名またはパスワードが正しくありません」</td><td>入力ミスの可能性が最も高い</td><td>大文字小文字、スペース、似た文字（<code>I/l/1</code>、<code>O/0</code>）の見間違いを確認。再試行は何度でも可（自動ロック機能は未実装、2026-04-18 時点）</td></tr><tr><td>「このアカウントは無効化されています」</td><td>店長がアカウントを停止</td><td>店長に連絡して有効化してもらう</td></tr><tr><td>「このテナントは無効化されています」</td><td>契約が止まっている</td><td>POSLA 運営（info@posla.jp）に連絡</td></tr><tr><td>「ユーザー名とパスワードは必須です」</td><td>片方が空欄</td><td>両方を入力</td></tr><tr><td>「通信エラーが発生しました」</td><td>Wi-Fi 切れ or サーバー障害</td><td>Wi-Fi 確認、1 分後再試行</td></tr><tr><td>「サーバーが空のレスポンスを返しました」</td><td>POSLA サーバー側の問題</td><td>5 分待って再試行。繰り返す場合 POSLA 運営に連絡</td></tr><tr><td>画面真っ白</td><td>ブラウザ or JavaScript エラー</td><td>Cmd+Shift+R で強制リロード</td></tr><tr><td>URL が違う</td><td>URL タイプミス</td><td>正しい URL: <code>https://eat.posla.jp/public/admin/index.html</code>（<code>/public/</code> プレフィックス必須）</td></tr></tbody></table><h3 id="_8-1-2-パスワードを忘れた場合" tabindex="-1">8-1-2. パスワードを忘れた場合 <a class="header-anchor" href="#_8-1-2-パスワードを忘れた場合" aria-label="Permalink to &quot;8-1-2. パスワードを忘れた場合&quot;">​</a></h3><p><strong>スタッフ（staff）が忘れた</strong>:</p><ol><li>店長に依頼</li><li>店長が管理画面（dashboard → スタッフ管理）で <strong>【パスワードリセット】</strong></li><li>新しい仮パスワードをスタッフに伝える</li><li>スタッフは次回ログイン後に自分で好きなパスワードに変更</li></ol><p><strong>店長（manager）が忘れた</strong>:</p><ol><li>オーナーに依頼</li><li>オーナーが owner-dashboard → ユーザー管理 で <strong>【パスワードリセット】</strong></li></ol><p><strong>オーナーが忘れた</strong>:</p><ol><li><code>info@posla.jp</code> に連絡</li><li>本人確認のため <strong>契約時の代表者名 + 契約時のメール</strong> を送る</li><li>POSLA 運営が 24 時間以内にリセット対応</li></ol><h3 id="_8-1-3-ログイン画面が開かない" tabindex="-1">8-1-3. ログイン画面が開かない <a class="header-anchor" href="#_8-1-3-ログイン画面が開かない" aria-label="Permalink to &quot;8-1-3. ログイン画面が開かない&quot;">​</a></h3><p><strong>症状</strong>: URL を開いても「管理画面」と表示されない</p><p><strong>対処</strong>:</p><ol><li>URL を再確認（<code>https://eat.posla.jp/public/admin/</code>）</li><li>Wi-Fi 接続確認</li><li>Chrome を完全終了してもう一度起動</li><li>違うブラウザで試す（Safari 等）</li><li>別のタブレット・スマホで試す（問題の切り分け）</li><li>全部ダメなら POSLA サーバー障害の可能性 → <code>info@posla.jp</code> に連絡</li></ol><hr><h2 id="_8-2-注文が入らない-画面が動かない" tabindex="-1">8-2. 注文が入らない / 画面が動かない <a class="header-anchor" href="#_8-2-注文が入らない-画面が動かない" aria-label="Permalink to &quot;8-2. 注文が入らない / 画面が動かない&quot;">​</a></h2><h3 id="_8-2-1-ハンディでの注文送信トラブル" tabindex="-1">8-2-1. ハンディでの注文送信トラブル <a class="header-anchor" href="#_8-2-1-ハンディでの注文送信トラブル" aria-label="Permalink to &quot;8-2-1. ハンディでの注文送信トラブル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>ボタンが反応しない</td><td>Wi-Fi 切れ or JavaScript エラー</td><td>Wi-Fi 確認 → Cmd+R リロード</td></tr><tr><td>「カートが空です」エラー</td><td>メニュー未選択で送信を押した</td><td>メニューをタップしてカートに追加してから送信</td></tr><tr><td>「テーブルを選択してください」</td><td>テーブル未選択</td><td>画面上部のドロップダウンからテーブル選択</td></tr><tr><td>「品切れが含まれています」</td><td>カート内に品切れ品目がある</td><td>該当品目をカートから削除して再送信</td></tr><tr><td>「セッションが無効です」</td><td>4 時間経過で切れた</td><td>再ログイン</td></tr><tr><td>「注文上限に達しています」</td><td>1 時間 / 1 テーブルの上限（20 件/10 分）超過</td><td>10 分待って再送信</td></tr><tr><td>タイムアウト</td><td>通信遅い</td><td>1 分待って再試行、別端末で試す</td></tr></tbody></table><h3 id="_8-2-2-セルフオーダーでお客様が注文できない" tabindex="-1">8-2-2. セルフオーダーでお客様が注文できない <a class="header-anchor" href="#_8-2-2-セルフオーダーでお客様が注文できない" aria-label="Permalink to &quot;8-2-2. セルフオーダーでお客様が注文できない&quot;">​</a></h3><p><strong>症状</strong>: お客様から「メニューで注文ボタンが押せない」と言われた</p><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>「ラストオーダー時刻を過ぎました」</td><td>設定されたラストオーダー時刻超過</td><td>マネージャーが店舗設定で LO 時刻を確認、必要なら延長</td></tr><tr><td>「セッションが期限切れです」</td><td>QR 読み込みから 4 時間経過</td><td>スタッフが新しい QR を発行（ハンディで 📲 QR 開放）</td></tr><tr><td>QR コードが読めない</td><td>QR が汚れ / 折れている</td><td>管理画面で QR 再印刷して貼り直し</td></tr><tr><td>画面が真っ白</td><td>スマホブラウザのバグ</td><td>お客様のスマホで Chrome / Safari を再起動してから QR を読み直す</td></tr></tbody></table><h3 id="_8-2-3-注文の送信後、キッチンに届いていない" tabindex="-1">8-2-3. 注文の送信後、キッチンに届いていない <a class="header-anchor" href="#_8-2-3-注文の送信後、キッチンに届いていない" aria-label="Permalink to &quot;8-2-3. 注文の送信後、キッチンに届いていない&quot;">​</a></h3><p><strong>症状</strong>: ハンディで注文送信したのに KDS 画面に現れない</p><p><strong>対処</strong>:</p><ol><li>KDS 画面をリロード（Cmd+Shift+R）</li><li>ステーション設定で <strong>「全品目」</strong> に切替（ステーション別に絞られている可能性）</li><li>ハンディの <strong>【注文履歴】</strong> タブで該当注文があるか確認</li><li>あるのに KDS に出ない → POSLA サーバー側の問題 → 運営に連絡</li></ol><hr><h2 id="_8-3-kds-に注文が表示されない" tabindex="-1">8-3. KDS に注文が表示されない <a class="header-anchor" href="#_8-3-kds-に注文が表示されない" aria-label="Permalink to &quot;8-3. KDS に注文が表示されない&quot;">​</a></h2><h3 id="_8-3-1-症状別対処" tabindex="-1">8-3-1. 症状別対処 <a class="header-anchor" href="#_8-3-1-症状別対処" aria-label="Permalink to &quot;8-3-1. 症状別対処&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>新規注文が全く入らない</td><td>ポーリング停止</td><td>ブラウザリロード。音声の「タップして開始」を実行していないと通知音が鳴らないので見落としている可能性</td></tr><tr><td>一部品目だけ表示されない</td><td>ステーション設定が絞り込んでいる</td><td>画面上部のステーションバーで <strong>【全品目】</strong> をタップ</td></tr><tr><td>音が鳴らない</td><td>音声未許可</td><td>初回 KDS 起動時の <strong>【タップして開始】</strong> が実行されていない。再ログインして必ずタップ</td></tr><tr><td>更新が遅い</td><td>3 秒間隔のポーリング</td><td>仕様通り。手動リフレッシュは不要だが、心配なら Cmd+R</td></tr><tr><td>調理ボタンが反応しない</td><td>通信エラー</td><td>3 秒待って状態が戻るか確認。戻らないならリロード</td></tr><tr><td>カードが古い情報のまま</td><td>ブラウザキャッシュ</td><td>Cmd+Shift+R で強制更新</td></tr></tbody></table><h3 id="_8-3-2-kds-画面が赤く点滅" tabindex="-1">8-3-2. KDS 画面が赤く点滅 <a class="header-anchor" href="#_8-3-2-kds-画面が赤く点滅" aria-label="Permalink to &quot;8-3-2. KDS 画面が赤く点滅&quot;">​</a></h3><p><strong>症状</strong>: 注文カードが赤く点滅している</p><p><strong>意味</strong>: 注文から <strong>20 分以上経過</strong>（<code>kds-renderer.js</code> L18-19）</p><p><strong>対処</strong>:</p><ol><li>急いで調理・提供</li><li>お客様にお詫び</li><li>遅延が続くなら人員配置・調理フローの見直し</li></ol><hr><h2 id="_8-4-カードリーダーが反応しない" tabindex="-1">8-4. カードリーダーが反応しない <a class="header-anchor" href="#_8-4-カードリーダーが反応しない" aria-label="Permalink to &quot;8-4. カードリーダーが反応しない&quot;">​</a></h2><h3 id="_8-4-1-手順で確認" tabindex="-1">8-4-1. 手順で確認 <a class="header-anchor" href="#_8-4-1-手順で確認" aria-label="Permalink to &quot;8-4-1. 手順で確認&quot;">​</a></h3><ol><li><strong>電源ランプ</strong>（本体正面）が緑色点灯しているか確認 <ul><li>消えている → 本体の電源ボタンを 2 秒長押し</li></ul></li><li><strong>Wi-Fi ランプ</strong>（青色）を確認 <ul><li>消えている → ルーターの電源を確認、必要なら再起動</li></ul></li><li>POSレジ画面右上の <strong>「Terminal 接続中」</strong> 表示を確認 <ul><li>未接続の場合 → 画面右上の <strong>【再検出】</strong> ボタン</li></ul></li><li>それでも無反応 → <strong>USB-C ケーブルでコンセントに接続</strong>（バッテリー切れ）</li><li>すべてダメなら Stripe 側の障害の可能性 → Stripe Dashboard を確認</li></ol><h3 id="_8-4-2-カードが通らない" tabindex="-1">8-4-2. カードが通らない <a class="header-anchor" href="#_8-4-2-カードが通らない" aria-label="Permalink to &quot;8-4-2. カードが通らない&quot;">​</a></h3><p><strong>症状</strong>: お客様のカードを当てても「決済失敗」</p><p><strong>対処</strong>:</p><ol><li><strong>別のカード</strong> で試す（カード側の問題切り分け）</li><li>挿入式カードなら <strong>IC チップ面を正しい向き</strong> で挿入</li><li>タッチ式なら <strong>カードをリーダーから離して再タッチ</strong></li><li>それでも失敗: 現金 / QR 決済に切り替え</li><li>お客様に無理強いしない（失敗は Stripe 側の判断）</li></ol><h3 id="_8-4-3-「-stripe-mismatch-」エラーが出た-2026-04-19-s3-修正" tabindex="-1">8-4-3. 「[STRIPE_MISMATCH]」エラーが出た（2026-04-19 S3 修正） <a class="header-anchor" href="#_8-4-3-「-stripe-mismatch-」エラーが出た-2026-04-19-s3-修正" aria-label="Permalink to &quot;8-4-3. 「[STRIPE_MISMATCH]」エラーが出た（2026-04-19 S3 修正）&quot;">​</a></h3><p><strong>症状</strong>: カード決済確定時に画面に <code>[STRIPE_MISMATCH]</code> または「決済結果が一致しません」と表示</p><p><strong>意味</strong>: Stripe Terminal から取得した決済結果（<code>payment_intent_id</code>）が、POSLA 側 DB に記録された ID と <strong>一致しなかった</strong>。決済確定の直前に何らかの異常（同時操作・Terminal 再接続・Stripe Dashboard での手動操作）が発生した可能性。</p><p><strong>対処</strong>（必須順序）:</p><ol><li><strong>会計を確定しない</strong>（現金 / QR 等への切り替えも一旦止める）</li><li>Stripe Dashboard → Payments で該当時刻の決済記録を確認</li><li>POSLA 運営（<code>info@posla.jp</code>）に連絡: <ul><li>店舗名・日時</li><li>お客様への請求金額（カード末尾 4 桁）</li><li>Stripe Dashboard の event_id（手元にあれば）</li></ul></li><li>運営側で Stripe ↔ POSLA の整合性を確認してから、改めて会計可否を判断</li></ol><div class="warning custom-block"><p class="custom-block-title">このエラーは「サーバー側の防御が効いた」サイン</p><p>2026-04-19 の S3 セキュリティ修正で導入した検証です。Stripe 側の決済結果と POSLA 側の記録が食い違ったまま会計を確定すると、二重請求や売上集計ズレが発生します。<strong><code>STRIPE_MISMATCH</code> が出たら必ず手を止めて運営に連絡</strong> してください。</p></div><p>詳細: <a href="./../tenant/18-security.html#18w-s3-セキュリティ修正一式2026-04-19">tenant 18 章 18.W S3 セキュリティ修正一式</a> / <a href="./../tenant/19-troubleshoot.html#19s3-s3-セキュリティ修正で追加された新エラーコード2026-04-19">tenant 19 章 19.S3</a></p><hr><h2 id="_8-5-wi-fi-が切れた-インターネットに繋がらない" tabindex="-1">8-5. Wi-Fi が切れた / インターネットに繋がらない <a class="header-anchor" href="#_8-5-wi-fi-が切れた-インターネットに繋がらない" aria-label="Permalink to &quot;8-5. Wi-Fi が切れた / インターネットに繋がらない&quot;">​</a></h2><h3 id="_8-5-1-症状の確認" tabindex="-1">8-5-1. 症状の確認 <a class="header-anchor" href="#_8-5-1-症状の確認" aria-label="Permalink to &quot;8-5-1. 症状の確認&quot;">​</a></h3><ol><li>タブレット画面右上の Wi-Fi アイコン確認 <ul><li>扇形 3 本 → 強い</li><li>扇形 1 本 → 弱い</li><li>バツマーク → 切れている</li></ul></li><li>ルーターのランプ確認（緑点灯が正常、赤は異常）</li></ol><h3 id="_8-5-2-対処-順番に試す" tabindex="-1">8-5-2. 対処（順番に試す） <a class="header-anchor" href="#_8-5-2-対処-順番に試す" aria-label="Permalink to &quot;8-5-2. 対処（順番に試す）&quot;">​</a></h3><ol><li><strong>タブレットの Wi-Fi を OFF → ON</strong>（設定アプリから）</li><li><strong>ルーターを再起動</strong>: <ul><li>ルーターの電源コンセントを <strong>30 秒間抜く</strong></li><li>再度挿す</li><li>緑ランプが全部点灯するまで待つ（約 1 分）</li></ul></li><li><strong>違う端末</strong>（スマホ等）で Wi-Fi に繋いでみる</li><li><strong>ブラウザで <code>google.com</code> を開いてみる</strong>（Wi-Fi は繋がっているけどインターネットがない場合）</li><li>それでもダメなら <strong>プロバイダ（NTT / ソフトバンク等）に連絡</strong></li></ol><h3 id="_8-5-3-オフライン時の-posla-の動き" tabindex="-1">8-5-3. オフライン時の POSLA の動き <a class="header-anchor" href="#_8-5-3-オフライン時の-posla-の動き" aria-label="Permalink to &quot;8-5-3. オフライン時の POSLA の動き&quot;">​</a></h3><p>Wi-Fi が切れている間の POSLA の挙動:</p><ul><li><strong>ハンディの注文</strong>: 自動的にブラウザに保存（<code>mt_pending_orders</code>）→ 再接続時に自動送信</li><li><strong>KDS</strong>: 画面上部にオフラインバナー表示 + 30 秒ポーリング</li><li><strong>POSレジ</strong>: 会計は失敗する（サーバーに届かない）</li><li><strong>セルフオーダー</strong>: お客様のスマホにも同様に保留注文が残る（24 時間以内に接続復旧すれば自動送信）</li></ul><hr><h2 id="_8-6-お客様の-qr-コードが読めない" tabindex="-1">8-6. お客様の QR コードが読めない <a class="header-anchor" href="#_8-6-お客様の-qr-コードが読めない" aria-label="Permalink to &quot;8-6. お客様の QR コードが読めない&quot;">​</a></h2><h3 id="_8-6-1-対処フロー" tabindex="-1">8-6-1. 対処フロー <a class="header-anchor" href="#_8-6-1-対処フロー" aria-label="Permalink to &quot;8-6-1. 対処フロー&quot;">​</a></h3><ol><li><strong>QR コードの物理確認</strong>: <ul><li>汚れていないか（拭く）</li><li>折れ目・シワがないか</li><li>印字がかすれていないか</li></ul></li><li><strong>QR 再印刷</strong>: <ul><li>dashboard → 【テーブル・フロア】 → 該当テーブルの【QR 印刷】</li><li>新しい QR をテーブルに貼る</li></ul></li><li><strong>それでも読めない場合のフォールバック</strong>: <ul><li>スタッフがハンディで <strong>【+ Walk-in】</strong> から手動着席</li><li>スタッフがお客様の注文を代わりに取る</li></ul></li></ol><h3 id="_8-6-2-お客様のスマホ側の問題" tabindex="-1">8-6-2. お客様のスマホ側の問題 <a class="header-anchor" href="#_8-6-2-お客様のスマホ側の問題" aria-label="Permalink to &quot;8-6-2. お客様のスマホ側の問題&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>カメラが QR 認識しない</td><td>古い iOS / Android</td><td>iOS 14+, Android 9+ 推奨</td></tr><tr><td>QR を読んでも URL が出ない</td><td>QR リーダーアプリの問題</td><td>カメラアプリで直接読み取り、または Chrome で読み取り</td></tr><tr><td>URL をタップしても開かない</td><td>ブラウザのポップアップブロック</td><td>Chrome のプライバシー設定を確認</td></tr></tbody></table><hr><h2 id="_8-7-間違えて注文を入れてしまった" tabindex="-1">8-7. 間違えて注文を入れてしまった <a class="header-anchor" href="#_8-7-間違えて注文を入れてしまった" aria-label="Permalink to &quot;8-7. 間違えて注文を入れてしまった&quot;">​</a></h2><h3 id="_8-7-1-注文履歴から編集-会計前" tabindex="-1">8-7-1. 注文履歴から編集（会計前） <a class="header-anchor" href="#_8-7-1-注文履歴から編集-会計前" aria-label="Permalink to &quot;8-7-1. 注文履歴から編集（会計前）&quot;">​</a></h3><ol><li>ハンディ画面の <strong>【注文履歴】</strong> タブ</li><li>該当注文をタップ</li><li><strong>【編集】</strong> ボタン</li><li>品目を追加・削除・数量変更</li><li><strong>【注文送信】</strong> で上書き（<strong>PATCH</strong> リクエスト）</li></ol><h3 id="_8-7-2-注文をキャンセル-会計前" tabindex="-1">8-7-2. 注文をキャンセル（会計前） <a class="header-anchor" href="#_8-7-2-注文をキャンセル-会計前" aria-label="Permalink to &quot;8-7-2. 注文をキャンセル（会計前）&quot;">​</a></h3><ol><li>KDS 画面で該当注文カードをタップ</li><li><strong>【取消】</strong> ボタン（赤）</li><li>確認ダイアログ → <strong>【OK】</strong></li><li>注文が <code>cancelled</code> ステータスに</li></ol><h3 id="_8-7-3-会計済みの注文の修正-返金対応" tabindex="-1">8-7-3. 会計済みの注文の修正（返金対応） <a class="header-anchor" href="#_8-7-3-会計済みの注文の修正-返金対応" aria-label="Permalink to &quot;8-7-3. 会計済みの注文の修正（返金対応）&quot;">​</a></h3><p>会計後は編集不可。8-8 返金を参照。</p><hr><h2 id="_8-8-返金が必要なとき" tabindex="-1">8-8. 返金が必要なとき <a class="header-anchor" href="#_8-8-返金が必要なとき" aria-label="Permalink to &quot;8-8. 返金が必要なとき&quot;">​</a></h2><h3 id="_8-8-1-対象者" tabindex="-1">8-8-1. 対象者 <a class="header-anchor" href="#_8-8-1-対象者" aria-label="Permalink to &quot;8-8-1. 対象者&quot;">​</a></h3><p>manager 以上のロール。staff はできない。</p><h3 id="_8-8-2-手順" tabindex="-1">8-8-2. 手順 <a class="header-anchor" href="#_8-8-2-手順" aria-label="Permalink to &quot;8-8-2. 手順&quot;">​</a></h3><ol><li>POSレジ画面右上の <strong>【📋 取引履歴】</strong> ボタン</li><li>該当取引をタップ</li><li><strong>【返金】</strong> ボタン（赤）</li><li>返金額 + 理由を入力</li><li><strong>【返金を確定】</strong></li><li><strong>確認ダイアログ</strong> で最終確認</li></ol><h3 id="_8-8-3-返金処理の中身" tabindex="-1">8-8-3. 返金処理の中身 <a class="header-anchor" href="#_8-8-3-返金処理の中身" aria-label="Permalink to &quot;8-8-3. 返金処理の中身&quot;">​</a></h3><ul><li><strong>Stripe カード決済</strong>: Stripe Refund API で自動返金。<strong>お客様のカードへ 3〜5 営業日で戻る</strong></li><li><strong>現金</strong>: POSLA は記録のみ。現金はスタッフが手渡しで返却</li><li><strong>QR 決済</strong>: PayPay / d払いの管理画面から別途返金（POSLA は記録のみ）</li></ul><h3 id="_8-8-4-部分返金" tabindex="-1">8-8-4. 部分返金 <a class="header-anchor" href="#_8-8-4-部分返金" aria-label="Permalink to &quot;8-8-4. 部分返金&quot;">​</a></h3><p>全額ではなく一部だけ返す場合:</p><ol><li>【返金】モーダルで <strong>金額</strong> 欄に返したい金額を入力（例: ¥1,000 のうち ¥500 だけ返す）</li><li>理由入力</li><li><strong>【返金を確定】</strong></li></ol><hr><h2 id="_8-9-パスワードがわからなくなった" tabindex="-1">8-9. パスワードがわからなくなった <a class="header-anchor" href="#_8-9-パスワードがわからなくなった" aria-label="Permalink to &quot;8-9. パスワードがわからなくなった&quot;">​</a></h2><p>8-1-2 を参照。</p><hr><h2 id="_8-10-画面が真っ白-エラーが出る" tabindex="-1">8-10. 画面が真っ白 / エラーが出る <a class="header-anchor" href="#_8-10-画面が真っ白-エラーが出る" aria-label="Permalink to &quot;8-10. 画面が真っ白 / エラーが出る&quot;">​</a></h2><h3 id="_8-10-1-対処-順番に試す" tabindex="-1">8-10-1. 対処（順番に試す） <a class="header-anchor" href="#_8-10-1-対処-順番に試す" aria-label="Permalink to &quot;8-10-1. 対処（順番に試す）&quot;">​</a></h3><ol><li><strong>ブラウザリロード</strong>（Cmd+Shift+R / Ctrl+Shift+F5）</li><li><strong>ブラウザのキャッシュクリア</strong>: <ul><li>Chrome: 設定 → プライバシー → 閲覧履歴データの削除</li><li>Safari: 設定 → Safari → 履歴と Web サイトデータを消去</li></ul></li><li><strong>違うブラウザ</strong>で試す（Chrome 推奨）</li><li><strong>タブレットを再起動</strong>（電源ボタン長押し → 再起動）</li><li><strong>違う端末</strong>で同じ操作を試す（問題の切り分け）</li><li>それでもダメなら <code>info@posla.jp</code> に連絡 <ul><li>エラー画面のスクリーンショット添付</li><li>使用ブラウザ + 端末情報（iPad Pro 12.9, iOS 17 等）</li></ul></li></ol><hr><h2 id="_8-11-プリンタが印刷しない" tabindex="-1">8-11. プリンタが印刷しない <a class="header-anchor" href="#_8-11-プリンタが印刷しない" aria-label="Permalink to &quot;8-11. プリンタが印刷しない&quot;">​</a></h2><h3 id="_8-11-1-チェックリスト" tabindex="-1">8-11-1. チェックリスト <a class="header-anchor" href="#_8-11-1-チェックリスト" aria-label="Permalink to &quot;8-11-1. チェックリスト&quot;">​</a></h3><ol><li><strong>プリンタの電源ランプ</strong> 緑点灯か確認</li><li><strong>用紙残量</strong> 確認（紙がなくなっていないか）</li><li><strong>紙詰まり</strong> 確認（紙送りゼロだと印字できない）</li><li><strong>プリンタ本体のカバー</strong> が正しく閉まっているか</li><li><strong>Wi-Fi 接続</strong> 確認（プリンタ画面の Wi-Fi マーク）</li><li>POSLA 管理画面で <strong>「プリンタ設定」→ 【🖨 テスト印刷】</strong> を実行</li></ol><h3 id="_8-11-2-テスト印刷で何も出ない場合" tabindex="-1">8-11-2. テスト印刷で何も出ない場合 <a class="header-anchor" href="#_8-11-2-テスト印刷で何も出ない場合" aria-label="Permalink to &quot;8-11-2. テスト印刷で何も出ない場合&quot;">​</a></h3><ol><li>プリンタ電源を切る → 10 秒待つ → 再度電源</li><li>プリンタの <strong>IP アドレスが変わっていないか確認</strong>（FEED ボタン長押しで再確認）</li><li>POSLA 管理画面でプリンタ設定の IP を更新</li></ol><p>詳細は <strong>26 章</strong> 参照。</p><hr><h2 id="_8-12-予約が反映されない-自動着席しない" tabindex="-1">8-12. 予約が反映されない / 自動着席しない <a class="header-anchor" href="#_8-12-予約が反映されない-自動着席しない" aria-label="Permalink to &quot;8-12. 予約が反映されない / 自動着席しない&quot;">​</a></h2><h3 id="_8-12-1-お客様が-qr-を読んでも自動着席しない" tabindex="-1">8-12-1. お客様が QR を読んでも自動着席しない <a class="header-anchor" href="#_8-12-1-お客様が-qr-を読んでも自動着席しない" aria-label="Permalink to &quot;8-12-1. お客様が QR を読んでも自動着席しない&quot;">​</a></h3><p><strong>原因の切り分け</strong>:</p><ol><li>ガント台帳でその予約を確認 <ul><li>テーブル割当済みか？ → 未割当ならスタッフが手動割当</li><li>予約時刻 ±30 分以内か？ → 範囲外なら手動着席</li><li>ステータス（confirmed / pending）か？ → キャンセルされていないか</li></ul></li><li>お客様が読んだ QR が <strong>正しいテーブル</strong> のものか？</li><li>上記クリアなら手動着席ボタン（ガントブロック → 🪑 着席）</li></ol><h3 id="_8-12-2-予約が-lp-で作れない" tabindex="-1">8-12-2. 予約が LP で作れない <a class="header-anchor" href="#_8-12-2-予約が-lp-で作れない" aria-label="Permalink to &quot;8-12-2. 予約が LP で作れない&quot;">​</a></h3><p><strong>原因</strong>:</p><ul><li>予約設定で <strong>「予約受付」</strong> が OFF になっている</li><li>スロット容量を使い切っている（その時刻の席が埋まっている）</li><li>予約金設定ありで Stripe 未設定（決済画面で止まる）</li></ul><p><strong>対処</strong>:</p><ol><li>管理画面の【予約管理】→【予約設定】で受付 ON を確認</li><li>Stripe 設定が完了しているか確認（21 章）</li></ol><hr><h2 id="_8-13-緊急連絡先" tabindex="-1">8-13. 緊急連絡先 <a class="header-anchor" href="#_8-13-緊急連絡先" aria-label="Permalink to &quot;8-13. 緊急連絡先&quot;">​</a></h2><h3 id="_8-13-1-トラブル種別と連絡先" tabindex="-1">8-13-1. トラブル種別と連絡先 <a class="header-anchor" href="#_8-13-1-トラブル種別と連絡先" aria-label="Permalink to &quot;8-13-1. トラブル種別と連絡先&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トラブル種別</th><th>連絡先</th></tr></thead><tbody><tr><td>POSLA 全般のトラブル</td><td><code>info@posla.jp</code>（24 時間以内に返答）</td></tr><tr><td>Stripe 決済トラブル</td><td>Stripe Dashboard からチャットサポート</td></tr><tr><td>スマレジ連携トラブル</td><td>スマレジ社のサポート窓口</td></tr><tr><td>Wi-Fi / ルータートラブル</td><td>プロバイダ（NTT フレッツ / ソフトバンク等）</td></tr></tbody></table><h3 id="_8-13-2-連絡時に伝えるべき情報" tabindex="-1">8-13-2. 連絡時に伝えるべき情報 <a class="header-anchor" href="#_8-13-2-連絡時に伝えるべき情報" aria-label="Permalink to &quot;8-13-2. 連絡時に伝えるべき情報&quot;">​</a></h3><ul><li>テナント名・店舗名</li><li>発生日時</li><li>症状（具体的に）</li><li>エラーメッセージ（あれば正確にコピー）</li><li>使用ブラウザと端末（例: iPad Pro 11-inch, iPadOS 17）</li><li>スクリーンショット（あれば添付）</li></ul><hr><h2 id="_8-14-付録-a-—-用語集" tabindex="-1">8-14. 付録 A — 用語集 <a class="header-anchor" href="#_8-14-付録-a-—-用語集" aria-label="Permalink to &quot;8-14. 付録 A — 用語集&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用語</th><th>意味</th></tr></thead><tbody><tr><td><strong>KDS</strong></td><td>Kitchen Display System、キッチン画面</td></tr><tr><td><strong>POS</strong></td><td>Point Of Sale、販売時点情報管理（レジ）</td></tr><tr><td><strong>ハンディ</strong></td><td>スタッフが持ち歩くモバイル端末</td></tr><tr><td><strong>セルフオーダー</strong></td><td>お客様のスマホで注文</td></tr><tr><td><strong>テイクアウト</strong></td><td>持ち帰り注文</td></tr><tr><td><strong>セッション</strong></td><td>着席〜退店までの一連の操作</td></tr><tr><td><strong>walk-in</strong></td><td>予約なしで来店</td></tr><tr><td><strong>no-show</strong></td><td>予約したのに来ない</td></tr><tr><td><strong>デポジット</strong></td><td>予約金（事前カード認証）</td></tr><tr><td><strong>Stripe</strong></td><td>決済代行サービス（POSLA 採用）</td></tr><tr><td><strong>Gemini</strong></td><td>Google の AI（POSLA で使用）</td></tr><tr><td><strong>テナント</strong></td><td>POSLA を契約している企業・店舗グループ</td></tr><tr><td><strong>ロール</strong></td><td>ユーザーの権限（owner / manager / staff / device）</td></tr><tr><td><strong>device アカウント</strong></td><td>端末専用のログイン（シフト・人件費対象外）</td></tr><tr><td><strong>サブセッション</strong></td><td>同じテーブルを複数グループで分割会計する仕組み</td></tr></tbody></table><hr><h2 id="_8-15-付録-b-—-ショートカットキー" tabindex="-1">8-15. 付録 B — ショートカットキー <a class="header-anchor" href="#_8-15-付録-b-—-ショートカットキー" aria-label="Permalink to &quot;8-15. 付録 B — ショートカットキー&quot;">​</a></h2><p>POSレジ画面（<code>cashier.html</code>）で使えるキーボードショートカット:</p><table tabindex="0"><thead><tr><th>キー</th><th>機能</th></tr></thead><tbody><tr><td>テンキー + Enter</td><td>会計確定</td></tr><tr><td>F1</td><td>現金モードに切替</td></tr><tr><td>F2</td><td>カードモードに切替</td></tr><tr><td>F3</td><td>QR モードに切替</td></tr><tr><td>J</td><td>取引履歴パネル</td></tr><tr><td>R</td><td>レシートプレビュー</td></tr></tbody></table><hr><h2 id="_8-16-付録-c-—-推奨機材と購入先" tabindex="-1">8-16. 付録 C — 推奨機材と購入先 <a class="header-anchor" href="#_8-16-付録-c-—-推奨機材と購入先" aria-label="Permalink to &quot;8-16. 付録 C — 推奨機材と購入先&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機材</th><th>推奨</th><th>購入先</th></tr></thead><tbody><tr><td>タブレット</td><td>iPad（10 インチ以上）</td><td>Apple 公式 / 家電量販店</td></tr><tr><td>カードリーダー</td><td>Stripe Reader S700</td><td>stripe.com/jp/terminal</td></tr><tr><td>プリンタ</td><td>Star mC-Print3 / Epson TM-m30III</td><td>Amazon / 楽天 / メーカー直販</td></tr><tr><td>Wi-Fi ルーター</td><td>家庭用で OK、業務用ならヤマハ</td><td>家電量販店</td></tr></tbody></table><hr><h2 id="_8-17-付録-d-—-ai-ヘルプデスクの使い方-2026-04-19-更新" tabindex="-1">8-17. 付録 D — AI ヘルプデスクの使い方（2026-04-19 更新） <a class="header-anchor" href="#_8-17-付録-d-—-ai-ヘルプデスクの使い方-2026-04-19-更新" aria-label="Permalink to &quot;8-17. 付録 D — AI ヘルプデスクの使い方（2026-04-19 更新）&quot;">​</a></h2><p>わからないことがあれば AI に聞くのが最も早い。<strong>マネージャー以上が管理画面で利用</strong>します。</p><ol><li>管理画面（<code>dashboard.html</code> / <code>owner-dashboard.html</code>）の <strong>右下にあるオレンジ色 ? ボタン</strong>（円形 FAB）を 1 タップ</li><li>チャットパネルが開く</li><li>質問を入力（例: 「パスワードを変更する方法は？」「<code>[E3024]</code> とは？」）</li><li>送信ボタンまたは Enter キー</li><li>数秒で AI がこのマニュアル全章 + エラーカタログから該当部分を探して回答</li></ol><div class="warning custom-block"><p class="custom-block-title">スタッフ用端末には AI ボタンはありません</p><p>KDS・POSレジ・ハンディには AI ヘルプデスク FAB を設置していません（業務集中のため）。スタッフが困ったらマネージャーに聞くフローです。</p></div><p>お客様側（セルフメニュー）にも AI があり、<strong>「このメニューに卵は入っていますか？」</strong> などの質問に回答します（AI ウェイター機能、こちらは別の AI）。</p><hr><h2 id="_8-18-付録-e-—-動画チュートリアル" tabindex="-1">8-18. 付録 E — 動画チュートリアル <a class="header-anchor" href="#_8-18-付録-e-—-動画チュートリアル" aria-label="Permalink to &quot;8-18. 付録 E — 動画チュートリアル&quot;">​</a></h2><p>（Phase 2 で動画コンテンツ追加予定）</p><hr><h2 id="_8-19-終わりに" tabindex="-1">8-19. 終わりに <a class="header-anchor" href="#_8-19-終わりに" aria-label="Permalink to &quot;8-19. 終わりに&quot;">​</a></h2><p>このマニュアルは随時更新されます。新機能追加や仕様変更時に各章が更新されます。</p><p><strong>困ったら</strong>:</p><ol><li>このマニュアルの該当章を読む</li><li>AI ヘルプデスクに質問する</li><li><code>info@posla.jp</code> に連絡する</li></ol><p>この順番で試してください。</p><p>お困りのことがあればいつでも <code>info@posla.jp</code> までご連絡ください。24 時間以内に回答します。</p>',155)])])}const p=r(o,[["render",d]]);export{b as __pageData,p as default};
